import React from "react";

const Layout = ({ children, pageTitle = "NexaLearn LMS" }) => {
  return (
    <div
      style={{
        minHeight: "100vh",
        backgroundColor: "#f5f5f5",
        backgroundImage:
          "url('https://www.transparenttextures.com/patterns/cubes.png')",
        backgroundRepeat: "repeat",
        fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
      }}
    >
      <header
        style={{
          backgroundColor: "#a71010",
          padding: "15px 20px",
          display: "flex",
          alignItems: "center",
          gap: "12px",
        }}
      >
        <img
          src="https://upload.wikimedia.org/wikipedia/en/thumb/7/7a/Koneru_Lakshmaiah_University_logo.png/220px-Koneru_Lakshmaiah_University_logo.png"
          alt="NEXA Logo"
          style={{ height: "40px" }}
        />
        <h1
          style={{
            color: "#fff",
            fontWeight: "700",
            fontSize: "1.4rem",
            margin: 0,
            userSelect: "none",
            flexGrow: 1,
            textTransform: "uppercase",
          }}
        >
          {pageTitle}
        </h1>
      </header>
      <main
        style={{
          maxWidth: "1200px",
          margin: "40px auto",
          backgroundColor: "#fff",
          boxShadow: "0 8px 24px rgba(0,0,0,0.1)",
          borderRadius: "6px",
          padding: "30px 40px",
          minHeight: "70vh",
        }}
      >
        {children}
      </main>
    </div>
  );
};

export default Layout;
